        end_time = time.perf_counter()

        logger = logging.getLogger(func.__module__)
        logger.info(f"{func.__name__} took {end_time - start_time:.4f} seconds")

        return result

    return wrapper


def memory_profile(func: Callable) -> Callable:
    """Decorator to profile memory usage of a function"""
    @functools.wraps(func)
    def wrapper(*args, **kwargs):
        process = psutil.Process(os.getpid())
        mem_before = process.memory_info().rss / 1024 / 1024  # MB

        result = func(*args, **kwargs)

        mem_after = process.memory_info().rss / 1024 / 1024  # MB
        logger = logging.getLogger(func.__module__)
        logger.info(f"{func.__name__} memory delta: {mem_after - mem_before:.2f} MB")

        return result

    return wrapper


def retry_on_exception(max_attempts: int = 3, delay: float = 1.0, backoff: float = 2.0):
    """Decorator to retry function on exception with exponential backoff"""
    def decorator(func: Callable) -> Callable:
        @functools.wraps(func)
        def wrapper(*args, **kwargs):
            logger = logging.getLogger(func.__module__)
            current_delay = delay

            for attempt in range(max_attempts):
                try:
                    return func(*args, **kwargs)
                except Exception as e:
                    if attempt == max_attempts - 1:
                        logger.error(f"Failed after {max_attempts} attempts")
                        raise

                    logger.warning(f"Attempt {attempt + 1} failed: {e}. Retrying in {current_delay}s...")
                    time.sleep(current_delay)
                    current_delay *= backoff

        return wrapper
    return decorator


# ==================== PART 3: Context Managers for Debugging ====================

@contextmanager
def debug_context(name: str):
    """Context manager for debugging specific code blocks"""
    logger = logging.getLogger(__name__)
    logger.debug(f"Entering {name}")
    start_time = time.perf_counter()

    try:
        yield
    except Exception as e:
        logger.exception(f"Exception in {name}: {e}")
        raise
    finally:
        elapsed = time.perf_counter() - start_time
        logger.debug(f"Exiting {name} (took {elapsed:.4f}s)")


@contextmanager
def suppress_and_log(*exceptions):
    """Context manager to suppress and log specific exceptions"""
    logger = logging.getLogger(__name__)
    try:
        yield
    except exceptions as e:
        logger.warning(f"Suppressed {e.__class__.__name__}: {e}")


@contextmanager
def profile_block(name: str):
    """Context manager for profiling code blocks"""
    profiler = cProfile.Profile()
    profiler.enable()

    try:
        yield
    finally:
        profiler.disable()
        s = io.StringIO()
        ps = pstats.Stats(profiler, stream=s).sort_stats('cumulative')
        ps.print_stats(10)  # Top 10 functions

        logger = logging.getLogger(__name__)
        logger.info(f"Profile for {name}:\n{s.getvalue()}")


# ==================== PART 4: Advanced Debugging Classes ====================

@dataclass
class DebugInfo:
    """Store detailed debug information about function calls"""
    function_name: str
    args: Tuple[Any, ...]
    kwargs: Dict[str, Any]
    start_time: float
    end_time: Optional[float] = None
    result: Optional[Any] = None
    exception: Optional[Exception] = None
    memory_before: Optional[float] = None
    memory_after: Optional[float] = None

    @property
    def duration(self) -> Optional[float]:
        if self.end_time:
            return self.end_time - self.start_time
        return None

    @property
    def memory_delta(self) -> Optional[float]:
        if self.memory_before and self.memory_after:
            return self.memory_after - self.memory_before
        return None


class DebugCollector:
    """Collect and analyze debug information from function calls"""

    def __init__(self):
        self.calls: List[DebugInfo] = []
        self._lock = threading.Lock()

    def collect(self, func: Callable) -> Callable:
        """Decorator to collect debug information"""
        @functools.wraps(func)
        def wrapper(*args, **kwargs):
            process = psutil.Process(os.getpid())
            mem_before = process.memory_info().rss / 1024 / 1024

            debug_info = DebugInfo(
                function_name=func.__name__,
                args=args,
                kwargs=kwargs,
                start_time=time.perf_counter(),
                memory_before=mem_before
            )

            try:
                result = func(*args, **kwargs)
                debug_info.result = result
            except Exception as e:
                debug_info.exception = e
                raise
            finally:
                debug_info.end_time = time.perf_counter()
                debug_info.memory_after = process.memory_info().rss / 1024 / 1024

                with self._lock:
                    self.calls.append(debug_info)

            return result

        return wrapper

    def get_stats(self) -> Dict[str, Any]:
        """Get statistics about collected calls"""
        with self._lock:
            if not self.calls:
                return {}

            total_calls = len(self.calls)
            failed_calls = sum(1 for call in self.calls if call.exception)
            total_time = sum(call.duration or 0 for call in self.calls)

            func_stats = defaultdict(lambda: {'count': 0, 'total_time': 0, 'failures': 0})

            for call in self.calls:
                stats = func_stats[call.function_name]
                stats['count'] += 1
                stats['total_time'] += call.duration or 0
                if call.exception:
                    stats['failures'] += 1

            return {
                'total_calls': total_calls,
                'failed_calls': failed_calls,
                'total_time': total_time,
                'function_stats': dict(func_stats)
            }


# ==================== PART 5: Memory Debugging ====================

class MemoryTracker:
    """Track memory allocations and detect potential leaks"""

    def __init__(self):
        self.objects = weakref.WeakValueDictionary()
        self.allocation_count = defaultdict(int)

    def track(self, obj: Any, name: str = None):
        """Track an object for memory debugging"""
        obj_id = id(obj)
        obj_type = type(obj).__name__

        if name:
            key = f"{name}_{obj_type}_{obj_id}"
        else:
            key = f"{obj_type}_{obj_id}"

        self.objects[key] = obj
        self.allocation_count[obj_type] += 1

    def get_stats(self) -> Dict[str, Any]:
        """Get memory tracking statistics"""
        gc.collect()  # Force garbage collection

        living_objects = defaultdict(int)
        for key in self.objects:
            obj_type = key.split('_')[0]
            living_objects[obj_type] += 1

        return {
            'allocation_count': dict(self.allocation_count),
            'living_objects': dict(living_objects),
            'total_tracked': len(self.objects)
        }


def find_memory_leaks(threshold: int = 1000):
    """Find potential memory leaks by analyzing object counts"""
    gc.collect()

    object_counts = defaultdict(int)
    for obj in gc.get_objects():
        object_counts[type(obj).__name__] += 1

    potential_leaks = {
        obj_type: count 
        for obj_type, count in object_counts.items() 
        if count > threshold
    }

    return potential_leaks


# ==================== PART 6: Async Debugging ====================

class AsyncDebugger:
    """Debugging tools for async code"""

    @staticmethod
    def trace_async(func: Callable) -> Callable:
        """Decorator to trace async function calls"""
        @functools.wraps(func)
        async def wrapper(*args, **kwargs):
            logger = logging.getLogger(func.__module__)
            task = asyncio.current_task()
            task_name = task.get_name() if task else 'Unknown'

            logger.debug(f"[Task: {task_name}] Starting {func.__name__}")
            start_time = time.perf_counter()

            try:
                result = await func(*args, **kwargs)
                elapsed = time.perf_counter() - start_time
                logger.debug(f"[Task: {task_name}] Completed {func.__name__} in {elapsed:.4f}s")
                return result
            except Exception as e:
                logger.exception(f"[Task: {task_name}] Failed {func.__name__}: {e}")
                raise

        return wrapper

    @staticmethod
    async def debug_gather(*tasks, return_exceptions=False):
        """Enhanced version of asyncio.gather with debugging"""
        logger = logging.getLogger(__name__)

        results = []
        for i, task in enumerate(tasks):
            try:
                logger.debug(f"Starting task {i}")
                result = await task
                logger.debug(f"Task {i} completed successfully")
                results.append(result)
            except Exception as e:
                logger.error(f"Task {i} failed: {e}")
                if return_exceptions:
                    results.append(e)
                else:
                    raise

        return results


# ==================== PART 7: Code Analysis and Introspection ====================

class CodeAnalyzer:
    """Analyze Python code for debugging purposes"""

    @staticmethod
    def disassemble_function(func: Callable):
        """Disassemble a function to bytecode"""
        print(f"\n=== Disassembly of {func.__name__} ===")
        dis.dis(func)

    @staticmethod
    def analyze_complexity(func: Callable) -> Dict[str, Any]:
        """Analyze function complexity"""
        source = inspect.getsource(func)
        tree = ast.parse(source)

        class ComplexityVisitor(ast.NodeVisitor):
            def __init__(self):
                self.complexity = 1  # Base complexity
                self.loops = 0
                self.conditions = 0
                self.functions = 0

            def visit_If(self, node):
                self.complexity += 1
                self.conditions += 1
                self.generic_visit(node)

            def visit_For(self, node):
                self.complexity += 1
                self.loops += 1
                self.generic_visit(node)

            def visit_While(self, node):
                self.complexity += 1
                self.loops += 1
                self.generic_visit(node)

            def visit_FunctionDef(self, node):
                self.functions += 1
                self.generic_visit(node)

        visitor = ComplexityVisitor()
        visitor.visit(tree)

        return {
            'cyclomatic_complexity': visitor.complexity,
            'loops': visitor.loops,
            'conditions': visitor.conditions,
            'nested_functions': visitor.functions
        }

    @staticmethod
    def trace_calls(func: Callable, depth: int = 1):
        """Trace all function calls made by a function"""
        calls = []

        def trace_func(frame, event, arg):
            if event == 'call' and frame.f_code.co_name != 'trace_func':
                calls.append({
                    'function': frame.f_code.co_name,
                    'filename': frame.f_code.co_filename,
                    'line': frame.f_lineno,
                    'locals': dict(frame.f_locals)
                })
            return trace_func if len(calls) < depth * 10 else None

        sys.settrace(trace_func)
        try:
            func()
        finally:
            sys.settrace(None)

        return calls


# ==================== PART 8: Exception Analysis ====================

class ExceptionAnalyzer:
    """Advanced exception analysis and debugging"""

    @staticmethod
    def analyze_exception(e: Exception) -> Dict[str, Any]:
        """Analyze an exception in detail"""
        tb = traceback.extract_tb(e.__traceback__)

        frames = []
        for frame in tb:
            frames.append({
                'filename': frame.filename,
                'line': frame.lineno,
                'function': frame.name,
                'code': frame.line
            })

        return {
            'type': type(e).__name__,
            'message': str(e),
            'args': e.args,
            'traceback': frames,
            'cause': ExceptionAnalyzer.analyze_exception(e.__cause__) if e.__cause__ else None,
            'context': ExceptionAnalyzer.analyze_exception(e.__context__) if e.__context__ else None
        }

    @staticmethod
    def format_exception_tree(e: Exception, indent: int = 0) -> str:
        """Format exception with full context chain"""
        lines = []
        prefix = "  " * indent

        lines.append(f"{prefix}{type(e).__name__}: {e}")

        if e.__cause__:
            lines.append(f"{prefix}Caused by:")
            lines.append(ExceptionAnalyzer.format_exception_tree(e.__cause__, indent + 1))

        if e.__context__ and e.__context__ is not e.__cause__:
            lines.append(f"{prefix}During handling of:")
            lines.append(ExceptionAnalyzer.format_exception_tree(e.__context__, indent + 1))

        return "\n".join(lines)


# ==================== PART 9: Performance Profiling ====================

class PerformanceProfiler:
    """Advanced performance profiling tools"""

    def __init__(self):
        self.timings = defaultdict(list)

    def profile_function(self, func: Callable) -> Callable:
        """Decorator for detailed performance profiling"""
        @functools.wraps(func)
        def wrapper(*args, **kwargs):
            start_time = time.perf_counter()
            start_cpu = time.process_time()

            result = func(*args, **kwargs)

            end_time = time.perf_counter()
            end_cpu = time.process_time()

            self.timings[func.__name__].append({
                'wall_time': end_time - start_time,
                'cpu_time': end_cpu - start_cpu,
                'timestamp': datetime.now()
            })

            return result

        return wrapper

    def get_stats(self, function_name: str = None) -> Dict[str, Any]:
        """Get performance statistics"""
        if function_name:
            timings = self.timings.get(function_name, [])
        else:
            timings = [t for times in self.timings.values() for t in times]

        if not timings:
            return {}

        wall_times = [t['wall_time'] for t in timings]
        cpu_times = [t['cpu_time'] for t in timings]

        return {
            'count': len(timings),
            'wall_time': {
                'total': sum(wall_times),
                'average': sum(wall_times) / len(wall_times),
                'min': min(wall_times),
                'max': max(wall_times)
            },
            'cpu_time': {
                'total': sum(cpu_times),
                'average': sum(cpu_times) / len(cpu_times),
                'min': min(cpu_times),
                'max': max(cpu_times)
            }
        }


# ==================== PART 10: Interactive Debugging Helpers ====================

class InteractiveDebugger:
    """Tools for interactive debugging sessions"""

    @staticmethod
    def explore_object(obj: Any, max_depth: int = 2):
        """Recursively explore object attributes"""
        def _explore(obj, depth=0, visited=None):
            if visited is None:
                visited = set()

            if depth > max_depth or id(obj) in visited:
                return "..."

            visited.add(id(obj))

            if isinstance(obj, (str, int, float, bool, type(None))):
                return obj
            elif isinstance(obj, (list, tuple)):
                return [_explore(item, depth + 1, visited) for item in obj[:5]]
            elif isinstance(obj, dict):
                return {k: _explore(v, depth + 1, visited) for k, v in list(obj.items())[:5]}
            else:
                result = {
                    '__type__': type(obj).__name__,
                    '__repr__': repr(obj)[:100]
                }

                for attr in dir(obj):
                    if not attr.startswith('_'):
                        try:
                            value = getattr(obj, attr)
                            if not callable(value):
                                result[attr] = _explore(value, depth + 1, visited)
                        except:
                            result[attr] = "<Error accessing attribute>"

                return result

        return _explore(obj)

    @staticmethod
    def watch_variable(name: str, frame=None):
        """Watch a variable for changes"""
        if frame is None:
            frame = inspect.currentframe().f_back

        initial_value = frame.f_locals.get(name, "<undefined>")
        print(f"Watching '{name}': {initial_value}")

        def trace_func(frame, event, arg):
            if event == 'line':
                current_value = frame.f_locals.get(name, "<undefined>")
                if current_value != initial_value:
                    print(f"'{name}' changed: {initial_value} -> {current_value}")
                    return None
            return trace_func

        sys.settrace(trace_func)


# ==================== EXAMPLE USAGE ====================

def example_buggy_function(x: int, y: int) -> float:
    """Example function with potential bugs for debugging practice"""
    # Potential division by zero
