#!/usr/bin/env python3
"""
Exercise 5.1: Complexity Analysis
Goal: Understand code complexity metrics
"""

import sys
sys.path.append('..')
from advanced_debugging_toolkit import CodeAnalyzer, setup_advanced_logging

# Setup logging
logger = setup_advanced_logging(__name__)

def simple_function(x):
    """Simple function with low complexity"""
    return x * 2

def moderate_function(data):
    """Moderate complexity with conditions"""
    result = 0
    for item in data:
        if item > 0:
            result += item
        else:
            result -= item
    return result

def complex_function(data):
    """High complexity function that needs refactoring"""
    result = 0
    for item in data:
        if item > 0:
            if item % 2 == 0:
                result += item
            else:
                for i in range(item):
                    if i % 3 == 0:
                        result += i
        else:
            if item < -10:
                for j in range(abs(item)):
                    if j % 5 == 0:
                        result -= j
            else:
                result -= item
    return result

def refactored_complex_function(data):
    """Refactored version with lower complexity"""
    def process_positive_even(item):
        return item

    def process_positive_odd(item):
        return sum(i for i in range(item) if i % 3 == 0)

    def process_large_negative(item):
        return -sum(j for j in range(abs(item)) if j % 5 == 0)

    result = 0
    for item in data:
        if item > 0:
            if item % 2 == 0:
                result += process_positive_even(item)
            else:
                result += process_positive_odd(item)
        elif item < -10:
            result += process_large_negative(item)
        else:
            result -= item

    return result

def deeply_nested_function(x, y, z):
    """Example of deeply nested code (bad practice)"""
    if x > 0:
        if y > 0:
            if z > 0:
                if x > y:
                    if y > z:
                        return x + y + z
                    else:
                        return x + y - z
                else:
                    if x > z:
                        return x - y + z
                    else:
                        return -x + y + z
            else:
                return x + y
        else:
            return x
    else:
        return 0

def main():
    print("=== Exercise 5.1: Complexity Analysis ===")
    print("Analyzing code complexity metrics...")
    print("-" * 50)

    # Create analyzer
    analyzer = CodeAnalyzer()

    # Functions to analyze
    functions = [
        (simple_function, "Simple Function"),
        (moderate_function, "Moderate Function"),
        (complex_function, "Complex Function"),
        (refactored_complex_function, "Refactored Complex Function"),
        (deeply_nested_function, "Deeply Nested Function")
    ]

    # Analyze each function
    for func, name in functions:
        print(f"\n--- {name} ---")

        # Get complexity metrics
        metrics = analyzer.analyze_complexity(func)

        print(f"Cyclomatic Complexity: {metrics['cyclomatic_complexity']}")
        print(f"Number of loops: {metrics['loops']}")
        print(f"Number of conditions: {metrics['conditions']}")
        print(f"Nested functions: {metrics['nested_functions']}")

        # Provide interpretation
        cc = metrics['cyclomatic_complexity']
        if cc <= 5:
            print("✓ Low complexity - Easy to test and maintain")
        elif cc <= 10:
            print("⚠ Moderate complexity - Consider refactoring")
        else:
            print("✗ High complexity - Should be refactored")

    # Demonstrate disassembly for deeper analysis
    print("\n--- Bytecode Analysis ---")
    print("Disassembling simple_function to show bytecode:")
    analyzer.disassemble_function(simple_function)

    # Test that refactored function produces same results
    print("\n--- Verification ---")
    test_data = [5, -3, 12, -15, 7, 0, -8, 20]
    original_result = complex_function(test_data)
    refactored_result = refactored_complex_function(test_data)

    print(f"Test data: {test_data}")
    print(f"Original result: {original_result}")
    print(f"Refactored result: {refactored_result}")
    print(f"Results match: {original_result == refactored_result}")

    print("\n💡 Complexity Analysis Insights:")
    print("   - Cyclomatic Complexity = 1 + conditions + loops")
    print("   - Lower complexity = easier to test and debug")
    print("   - Aim for complexity < 10 per function")
    print("   - Extract nested logic into separate functions")
    print("   - Use guard clauses to reduce nesting")

if __name__ == "__main__":
    main()

