Goal: Understand complex error scenarios
"""

import sys
import json
sys.path.append('..')
from advanced_debugging_toolkit import ExceptionAnalyzer, setup_advanced_logging

# Setup logging
logger = setup_advanced_logging(__name__)

def parse_config(config_str):
    """Parse configuration with detailed error handling"""
    try:
        data = json.loads(config_str)

        # Validate required fields
        if 'settings' not in data:
            raise KeyError('settings')

        if 'value' not in data['settings']:
            raise KeyError('settings.value')

        value = data['settings']['value']

        # Type validation
        if not isinstance(value, (int, float)):
            raise TypeError(f"Expected number, got {type(value).__name__}")

        return value

    except json.JSONDecodeError as e:
        raise ValueError(f"Invalid JSON format at line {e.lineno}, column {e.colno}") from e
    except KeyError as e:
        raise ValueError(f"Missing required field: {e}") from e
    except TypeError as e:
        raise ValueError(f"Type error: {e}") from e

def load_configuration(filename):
    """Load configuration from file with error handling"""
    try:
        with open(filename, 'r') as f:
            content = f.read()

        if not content.strip():
            raise ValueError("Configuration file is empty")

        return parse_config(content)

    except FileNotFoundError as e:
        raise RuntimeError(f"Configuration file not found: {filename}") from e
    except PermissionError as e:
        raise RuntimeError(f"Permission denied reading: {filename}") from e
    except ValueError as e:
        raise RuntimeError(f"Configuration error in {filename}") from e

def initialize_system(config_path):
    """Initialize system with configuration"""
    try:
        config_value = load_configuration(config_path)

        if config_value < 0:
            raise ValueError("Configuration value must be positive")

        # Simulate system initialization
        if config_value > 1000:
            raise OverflowError("Configuration value too large for system")

        return f"System initialized with value: {config_value}"

    except RuntimeError as e:
        raise SystemError("System initialization failed") from e
    except (ValueError, OverflowError) as e:
        raise SystemError(f"Invalid configuration: {e}") from e

def demonstrate_exception_scenarios():
    """Demonstrate various exception scenarios"""
    scenarios = [
        # Scenario 1: File not found
        ("nonexistent.json", "File not found scenario"),

        # Scenario 2: Invalid JSON
        ("invalid.json", "Invalid JSON scenario"),

        # Scenario 3: Missing field
        ("missing_field.json", "Missing field scenario"),

        # Scenario 4: Wrong type
        ("wrong_type.json", "Wrong type scenario"),

        # Scenario 5: Valid but out of range
        ("out_of_range.json", "Out of range scenario")
    ]

    # Create test files
    test_files = {
        "invalid.json": "{ invalid json }",
        "missing_field.json": '{"other": "data"}',
        "wrong_type.json": '{"settings": {"value": "not a number"}}',
        "out_of_range.json": '{"settings": {"value": 2000}}'
    }

    for filename, content in test_files.items():
        with open(filename, 'w') as f:
            f.write(content)

    # Test each scenario
    for filename, description in scenarios:
        print(f"\n--- {description} ---")
        try:
            result = initialize_system(filename)
            print(f"Success: {result}")
        except Exception as e:
            print(f"\nException caught: {type(e).__name__}")
            print("\nException Tree:")
            print(ExceptionAnalyzer.format_exception_tree(e))

            print("\nDetailed Analysis:")
            analysis = ExceptionAnalyzer.analyze_exception(e)
            print(f"  Root cause: {analysis['type']}: {analysis['message']}")
            print(f"  Exception chain depth: {len(analysis['traceback'])}")

            # Show cause chain
            current = analysis
            depth = 0
            while current.get('cause'):
                depth += 1
                current = current['cause']
                print(f"  Caused by ({depth}): {current['type']}: {current['message']}")

    # Cleanup test files
    import os
    for filename in test_files:
        if os.path.exists(filename):
            os.remove(filename)

def demonstrate_context_vs_cause():
    """Demonstrate the difference between __cause__ and __context__"""
    print("\n--- Context vs Cause ---")

    # Example 1: Explicit cause (raise ... from ...)
    try:
        try:
            1 / 0
        except ZeroDivisionError as e:
            raise ValueError("Cannot divide") from e
    except ValueError as e:
        print("Example 1 - Explicit cause:")
        print(ExceptionAnalyzer.format_exception_tree(e))

    # Example 2: Implicit context
    try:
        try:
            1 / 0
        except ZeroDivisionError:
            raise ValueError("Cannot divide")  # No 'from'
    except ValueError as e:
        print("\nExample 2 - Implicit context:")
        print(ExceptionAnalyzer.format_exception_tree(e))

def main():
    print("=== Exercise 6.1: Exception Chain Analysis ===")
    print("Understanding complex error scenarios...")
    print("-" * 50)

    # Demonstrate various exception scenarios
    demonstrate_exception_scenarios()

    # Show context vs cause
    demonstrate_context_vs_cause()

    print("\n💡 Exception Analysis Insights:")
    print("   - Use 'raise ... from ...' for explicit exception chains")
    print("   - Exception chains preserve the full error context")
    print("   - __cause__ is set by 'from', __context__ is automatic")
    print("   - Analyze the root cause, not just the final exception")
    print("   - Good error messages make debugging much easier")

if __name__ == "__main__":
    main()

