"""
Exercise Runner
Main script to run all debugging exercises with menu selection
"""

import os
import sys
import importlib.util
from pathlib import Path

def get_exercise_files():
    """Get all exercise files in the current directory"""
    exercises = []
    exercise_dir = Path(__file__).parent

    for file in sorted(exercise_dir.glob("exercise_*.py")):
        if file.name != "run_exercises.py":
            exercises.append(file)

    return exercises

def load_and_run_exercise(exercise_file):
    """Load and run a specific exercise"""
    try:
        # Load the module
        spec = importlib.util.spec_from_file_location("exercise", exercise_file)
        module = importlib.util.module_from_spec(spec)

        # Add the parent directory to sys.path temporarily
        parent_dir = str(exercise_file.parent.parent)
        if parent_dir not in sys.path:
            sys.path.insert(0, parent_dir)

        # Execute the module
        spec.loader.exec_module(module)

        # Run the main function if it exists
        if hasattr(module, 'main'):
            module.main()
        else:
            print(f"Warning: {exercise_file.name} has no main() function")

    except Exception as e:
        print(f"Error running {exercise_file.name}: {e}")
        import traceback
        traceback.print_exc()

def display_menu(exercises):
    """Display the exercise menu"""
    print("\n" + "=" * 60)
    print("🐛 PYTHON DEBUGGING EXERCISES MENU")
    print("=" * 60)

    # Group exercises by level
    levels = {}
    for i, exercise in enumerate(exercises, 1):
        name = exercise.stem
        if 'exercise_1' in name:
            level = "Level 1: Basic Debugging"
        elif 'exercise_2' in name:
            level = "Level 2: Context-Based Debugging"
        elif 'exercise_3' in name:
            level = "Level 3: Advanced Patterns"
        elif 'exercise_4' in name:
            level = "Level 4: Async Debugging"
        elif 'exercise_5' in name:
            level = "Level 5: Code Analysis"
        elif 'exercise_6' in name:
            level = "Level 6: Exception Analysis"
        elif 'exercise_7' in name:
            level = "Level 7: Performance Profiling"
        elif 'exercise_8' in name:
            level = "Level 8: Interactive Debugging"
        elif 'exercise_9' in name:
            level = "Level 9: Real-World Scenarios"
        elif 'exercise_10' in name:
            level = "Level 10: Master Challenge"
        else:
            level = "Other Exercises"

        if level not in levels:
            levels[level] = []

        levels[level].append((i, exercise))

    # Display grouped menu
    for level, exercise_list in levels.items():
        print(f"\n{level}:")
        for i, exercise in exercise_list:
            # Extract exercise name from filename
            name_parts = exercise.stem.replace('exercise_', '').replace('_', ' ').title()
            print(f"  {i:2d}. {name_parts}")

    print(f"\n  {len(exercises) + 1:2d}. Run ALL exercises")
    print(f"   0. Exit")
    print("\n" + "=" * 60)

def run_all_exercises(exercises):
    """Run all exercises in sequence"""
    print("\n🚀 Running ALL exercises...")
    print("=" * 60)

    for i, exercise in enumerate(exercises, 1):
        print(f"\n>>> Running Exercise {i}: {exercise.stem}")
        print("-" * 40)

        try:
            load_and_run_exercise(exercise)
        except KeyboardInterrupt:
            print("\n⚠️  Exercise interrupted by user")
            break
        except Exception as e:
            print(f"❌ Exercise failed: {e}")

        print("-" * 40)
        print(f">>> Exercise {i} completed")

        # Pause between exercises
        if i < len(exercises):
            input("\nPress Enter to continue to next exercise...")

def main():
    """Main menu loop"""
    exercises = get_exercise_files()

    if not exercises:
        print("No exercise files found!")
        return

    print("🐛 Welcome to the Python Debugging Exercises!")
    print("These exercises will help you master debugging techniques.")

    while True:
        try:
            display_menu(exercises)

            choice = input("\nSelect an exercise (0 to exit): ").strip()

            if choice == '0':
                print("\n👋 Happy debugging! Keep practicing!")
                break

            try:
                choice_num = int(choice)
            except ValueError:
                print("❌ Please enter a valid number")
                continue

            if choice_num == len(exercises) + 1:
                # Run all exercises
                run_all_exercises(exercises)
                continue

            if 1 <= choice_num <= len(exercises):
                selected_exercise = exercises[choice_num - 1]
                print(f"\n🚀 Running: {selected_exercise.stem}")
                print("=" * 60)

                load_and_run_exercise(selected_exercise)

                print("\n" + "=" * 60)
                print(f"✅ Exercise completed: {selected_exercise.stem}")

                input("\nPress Enter to return to menu...")
            else:
                print("❌ Invalid choice. Please try again.")

        except KeyboardInterrupt:
            print("\n\n👋 Goodbye!")
            break
        except Exception as e:
            print(f"\n❌ An error occurred: {e}")
            input("Press Enter to continue...")

if __name__ == "__main__":
    main()

